VALUES
  ('diplomatic-823d6974-moex-00216', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '有關憲法訴訟法施行前之司法院大法官解釋效力，下列敘述何者錯誤？', '["拘束全國各機關", "拘束全國人民", "依人民聲請所為之解釋，對聲請人據以聲請之案件，具有效力", "如宣告法規範違憲，該法規範自始失其效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00217', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '在美、中二國的兩岸政策上，2021年10月12日，時任美國國防部發言人柯比（JohnKirby）曾經表示： 「美國長期遵循『一中政策』（OneChinaPolicy），這和中共『一中原則』（OneChinaPrinciple）不同。」 有關美國的「一中政策」，下列敘述何者錯誤？', '["1979年的《建交公報》，美、中二國均同意：「世界上只有一個中國，中華人民共和國是中國的唯一 合法政府」", "美、中二國1972年的《上海公報》及1979年的《建交公報》均有提到：「雙方都希望減少國際軍事衝 突的危險」。因此，2022年10月17日，美國國務卿布林肯提到：「美國一中政策不會改變，但其核心 是承諾和平解決分歧。」", "為了避免臺海衝突，美國同意扮演兩岸調停人的角色", "在「一中原則」下，北京宣稱對臺灣擁有主權，但在「一中政策」下，美方對臺灣主權不持立場"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00218', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '2022年8月中共國台辦發表了第三份對臺政策「白皮書」：《臺灣問題與新時代中國統一事業》，顯示出 中共對臺政策的一些微妙變化。下列何者並非其中微妙變化之處？', '["第三份白皮書提出的一國兩制方案中，並未提及「臺灣可以有自己的軍隊」", "第三份白皮書重新提出1983年鄧小平的一國兩制方案：「要實現統一，就要有一個適當的方式，所 以我建議舉行兩黨平等會談，實行第三次合作，而不提中央和地方談判。」", "第三份白皮書提出的一國兩制方案中，並未提及中國大陸「不派軍隊也不派行政人員駐臺」", "第三份白皮書中，並未再提及「在一個中國的前提下，什麼問題都可以談」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00219', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '北京雖然至今仍宣示希望能「和平統一」臺灣，但至今依然堅持不承諾放棄使用武力來解決臺灣問題。 北京曾經宣示幾個可能對臺灣使用武力的理由，下列何者並不是其中宣示過的理由？', '["臺灣無限期拖延統一的政治談判", "臺灣內部出現動亂", "臺灣有意義的參與聯合國相關國際組織", "外國勢力介入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00220', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '有關中共「外聯部」的敘述，下列何者錯誤？', '["該部與中共外交部的人事互不流通", "全名是中國共產黨中央委員會對外聯絡部", "是負責「政黨外交」的單位", "與中共外交部相同，屬於「正部級」的位階"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00221', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '兩岸自1990年代以來，便一直有談判《兩岸軍事互信機制》的呼聲和提議，然而至今一直沒有進展。 下列何者是導致其無法進展的原因？', '["北京堅持兩岸軍事互信之建立上，須先預設「一個中國原則」政治框架前提，這難免會被臺灣人民 視為是北京的政治統戰", "美國反對兩岸軍事互信機制的談判", "北京認為軍事互信機制協議的談判，是屬於國家之間的談判，北京不認為臺灣是一個國家，因此始 終反對和臺灣進行軍事互信機制的談判", "兩岸均認為軍事互信機制的用處不大，因此無意進行談判"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00222', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '習近平2019年1月2日在《告臺灣同胞書》40週年紀念會上，提出對臺五大政策（簡稱《習五點》），至 今仍然是中共目前對臺政策最重要的指導方針。下列何者不是《習五點》的內容？', '["習近平定義何謂「九二共識」：「70年來，我們秉持求同存異精神，推動兩岸雙方在一個中國的基礎 上達成兩岸同屬一個中國，共同努力謀求國家統一的九二共識」", "探索「一國兩制臺灣方案」，豐富和平統一實踐", "中國人不打中國人，……，我們不承諾放棄使用武力，保留採取一切必要措施的選項", "接受「一中各表」的九二共識，來推動兩岸的和平統一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00223', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '近年來兩岸經濟關係的變化，下列敘述何者錯誤？', '["臺商對中國大陸投資占海外投資比率，在2010年曾飆升至83.8%的高點，到2022年則大幅下降、占 投資總額34%，到了2023年更降至11.4%、創30年新低", "2022年我國出口至中國大陸的貿易額，ECFA相關貨品占了約2,000億元，占整體貿易額5,000億元的 大概40%左右，亦使北京以ECFA相關貨品的禁運來脅迫臺灣，可以對臺灣經濟構成重大傷害", "2020年對中、港、澳出口占臺灣出口比重43.9%，到了2024年1至4月比重下降到30.7%，這是過去22 年來同季最低", "2024年1至4月臺灣對美國出口占總出口比重則上升到22.3%，對東協升至20.2%，分別是24年來以及 歷年同季的最高水準。主因自2018年後美中貿易戰開展以來，臺灣企業在美國客戶的督促下，一直 在實現生產地多元化，部分集中在中國大陸的產能，轉移到臺灣、美國、東南亞等地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00224', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '臺灣面臨中共對臺複合性施壓，為了展現守護國家的決心，賴清德總統提出「和平四大支柱行動方案」， 下列何者不是其中的方案？', '["談判兩岸軍事互信機制與和平協議", "強化國防和不對稱戰力，建立臺灣的嚇阻力量", "深化與國際社會和民主國家的合作關係", "強化經濟安全和供應鏈的韌性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00225', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '2022年10月中國共產黨召開第二十次全國代表大會（簡稱中共二十大），下列敘述何者錯誤？', '["二十大習近平的《政治報告》中，自2002年中共十六大之後，再次出現「不承諾放棄使用武力」來 處理臺灣問題。十七至十九屆《政治報告》均未提及「不承諾放棄使用武力」此語", "7位中共政治局常委全是「習近平派」，習近平權力一把抓", "習近平在二十大上破例連任第三屆中共總書記，打破鄧小平時代以來只做兩屆10年的慣例", "習近平在二十大上，延續慣例做了5年後二十一大的接班人安排，承諾不會爭取第四個任期"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL)
